        ethUsd: 2400.5
      }
    };

    const event: RealtimeEvent = {
      type: "update",
      canisterId: "rdmx6-jaaaa-aaaaa-aaadq-cai",
      changes: {
        tier: "low"
      },
      timestamp: 1_710_000_000_000
